/bin/zsh -lc "git remote -v; git branch -a; git show --stat --oneline HEAD; git show HEAD:sympy/core/tests/test_numbers.py | sed -n '360,385p'; ./.venv/bin/python - <<'PY'
from sympy import Rational, Float
cases = [
    ('0.5', '100'), ('1.5', '1.5'), ('1.5', 1.5), (1.5, '1.5'),
    (0.1, 1), (1, 0.1), (Rational(1, 2), Rational(3, 4)),
]
for p, q in cases:
    try:
        print(repr(p), repr(q), '=>', Rational(p, q))
    except Exception as exc:
        print(repr(p), repr(q), '=>', type(exc).__name__, exc)
print(\"Float('_1'):\", Float('_1'))
PY"

